/*!50003 CREATE*/ /*!50017 DEFINER=`root`@`localhost`*/ /*!50003 TRIGGER `after_sku_insert` AFTER INSERT ON `sku_san_pham` FOR EACH ROW BEGIN
    UPDATE san_pham sp
    SET sp.so_luong_ton = (
        SELECT COALESCE(SUM(so_luong_ton), 0)
        FROM sku_san_pham 
        WHERE san_pham_id = NEW.san_pham_id
        AND trang_thai = 'DANG_BAN'
    )
    WHERE sp.id = NEW.san_pham_id;
END */;;
DELIMITER ;
